        adjE[u].push({ v: v, weight: cost });
        adjE[v].push({ v: u, weight: cost });

        // Graph C (Carrying Apples): weight = cost * tax
        const weightC = cost * tax;
        adjC[u].push({ v: v, weight: weightC });
        adjC[v].push({ v: u, weight: weightC });
    }

