    }

    // DistC[i][j]: min cost from i to j when carrying apples
    const DistC: number[][] = [];
    for (let i = 0; i < n; i++) {
        DistC.push(dijkstra(adjC, i));
    }

    // 4. Calculate Final Answer
    const ans: number[] = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at store i
        let minCost = prices[i];

        // Option 2: Travel to store j, buy, and return to i
        for (let j = 0; j < n; j++) {
