/**
 * Helper class for Min Priority Queue used in Dijkstra's algorithm.
 * Stores [distance, node] pairs, prioritizing lower distance.
 */
class MinPriorityQueue {
    private heap: [number, number][] = [];

    size(): number {
        return this.heap.length;
    }

    isEmpty(): boolean {
        return this.size() === 0;
    }

    enqueue(element: [number, number]): void {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    dequeue(): [number, number] | undefined {
        if (this.isEmpty()) return undefined;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop()!;
        this.bubbleDown(0);
        return min;
    }

    private bubbleUp(index: number): void {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            // Compare based on distance (index 0 of the pair)
            if (this.heap[index][0] < this.heap[parentIndex][0]) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    private bubbleDown(index: number): void {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            // Compare based on distance
            if (leftChildIndex <= lastIndex && this.heap[leftChildIndex][0] < this.heap[smallest][0]) {
                smallest = leftChildIndex;
            }
            if (rightChildIndex <= lastIndex && this.heap[rightChildIndex][0] < this.heap[smallest][0]) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            } else {
                break;
            }
        }
    }
}

/**
 * Runs Dijkstra's algorithm from a single source node.
 * @param n Number of nodes.
 * @param adj Adjacency list: adj[u] = [[v1, weight1], [v2, weight2], ...].
 * @param startNode The source node.
 * @returns An array of minimum distances from startNode to all other nodes.
 */
function dijkstra(n: number, adj: [number, number][][], startNode: number): number[] {
    // Use a large number for Infinity, ensuring it handles sums of costs (up to 10^12)
    const INF = 1e18; 
    const dist: number[] = new Array(n).fill(INF);
    const pq = new MinPriorityQueue();

    dist[startNode] = 0;
    // Enqueue [distance, node]
    pq.enqueue([0, startNode]);

    while (!pq.isEmpty()) {
        const [d, u] = pq.dequeue()!;

        if (d > dist[u]) continue;

        for (const [v, weight] of adj[u]) {
            const newDist = dist[u] + weight;
            if (newDist < dist[v]) {
                dist[v] = newDist;
                pq.enqueue([newDist, v]);
            }
        }
    }
    return dist;
}


